import { useRef, type PropsWithChildren } from 'react';

import { DynamicTooltip } from './DynamicTooltip.js';
import { useChartActionsMenu } from '../../series-action/hooks/useChartActionsMenu.js';
import { ActionSelectionContext } from '../../tooltip/context/ActionSelectionContext.js';
import { ChartTooltipMetadataContext } from '../../tooltip/context/ChartTooltipMetadataContext.js';

export const LegacyTemplateTooltip = (
  props: PropsWithChildren<{
    pinned: boolean;
    absoluteX: number;
    absoluteY: number;
  }>,
) => {
  const { absoluteX, absoluteY, pinned } = props;
  const tooltipRef = useRef<HTMLDivElement>(null);
  const {
    selectedItem: selectedItemId,
    actionsMenuRef,
    updateSelectedItem,
  } = useChartActionsMenu();

  if (!props.children) {
    return;
  }

  return (
    <ActionSelectionContext.Provider
      value={{ selectedItemId, actionsMenuRef, updateSelectedItem }}
    >
      <ChartTooltipMetadataContext.Provider value={{ tooltipRef }}>
        <DynamicTooltip
          pinned={pinned}
          absoluteX={absoluteX}
          absoluteY={absoluteY}
        >
          <div ref={tooltipRef}>{props.children}</div>
        </DynamicTooltip>
      </ChartTooltipMetadataContext.Provider>
    </ActionSelectionContext.Provider>
  );
};
